db.shipments.aggregate([
    { "$match": { "destination.arrivalTime": { "$exists": true } } },
    { "$project": { "duration": { "$subtract": ["$destination.arrivalTime", "$origin.departureTime"] } } },
    { "$group": { "_id": null, "avgDuration": { "$avg": "$duration" } } }
])

